// Simple inheritance
class Derived : public Base { /* ... */ };

// Multiple inheritance
class Derived : public Base1, public Base2 { /* ... */ };

class Base {
public:
    int x;
    void SetX(int value);
};
class Derived : public Base {
    int y;
public:
    void SetY(int value);
};

void main() {
    Derived d;
    d.SetX(100);  // inherited from Base
    d.x = 10;     // inherited public member
    d.SetY(200);  // own method
}

struct A { A(int x) { printf("ctor: A\n"); } ~A() { printf("dtor: A\n"); } };
struct B { B()      { printf("ctor: B\n"); } ~B() { printf("dtor: B\n"); } };
struct C { C(bool)  { printf("ctor: C\n"); } ~C() { printf("dtor: C\n"); } };
struct D { D(bool)  { printf("ctor: D\n"); } ~D() { printf("dtor: D\n"); } };

class E : public B, public A {
    C c;
    D d;
    int v1, v2;
public:
    // Initializer list order does NOT change construction order!
    E() : d(true), A(100), c(true), B(), v2(100), v1(20) {
        printf("ctor: E\n");
    }
    ~E() { printf("dtor: E\n"); }
};
// Output: B, A, C, D, (v1, v2), E -- then reverse for destructors

class Figure {
public:
    virtual void Draw() { printf("Figure"); }
    virtual ~Figure() { printf("Delete Figure\n"); }  // Virtual destructor!
};
class Circle : public Figure {
public:
    void Draw() { printf("Circle"); }
    ~Circle() { printf("Delete Circle\n"); }
};
class Square : public Figure {
public:
    void Draw() { printf("Square"); }
    ~Square() { printf("Delete Square\n"); }
};

void main() {
    Figure *f[2];
    f[0] = new Circle();
    f[1] = new Square();
    for (int i = 0; i < 2; i++) {
        f[i]->Draw();     // Polymorphism: Circle, Square
        delete f[i];      // Virtual dtor: Circle+Figure, Square+Figure
    }
}

struct A {
    virtual bool Odd(int x) = 0;  // Pure virtual
};
struct B : public A {
    // override: ensures we correctly override A::Odd
    // final: prevents C from overriding this
    virtual bool Odd(int x) override final { return x % 2 == 0; }
};
struct C : public B {
    // ERROR: 'B::Odd' declared as 'final' cannot be overridden
    // virtual bool Odd(int x) { return x % 3 == 0; }
};

// final on class: prevents inheritance entirely
struct D final : public A {
    bool Odd(int x) override { return x % 2 != 0; }
};
// ERROR: 'E' cannot inherit from 'D' as it has been declared 'final'
// struct E : public D { };

class A {
public:
    int x, y;
    virtual int Suma()      { return x + y; }
    virtual int Diferenta() { return x - y; }
    virtual int Produs()    { return x * y; }
};
class B : public A {
public:
    int Suma() { return 1; }  // Overrides A::Suma
};

// VTable for A: [&A::Suma, &A::Diferenta, &A::Produs]
// VTable for B: [&B::Suma, &A::Diferenta, &A::Produs]
//                ^^^^^^^^ -- only Suma is replaced

void main() {
    B b; b.x = 1; b.y = 2;
    A* a = &b;
    int x = a->Suma();      // Calls B::Suma via vtable => 1
    int y = a->Diferenta(); // Calls A::Diferenta via vtable => -1
}

class A {
public:
    virtual A* clone() { return new A(); }
};
class B : public A {
public:
    virtual B* clone() { return new B(); }  // Covariant: B* derives from A*
};
